 1	import { Button, Popper } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { DataSource, PacketLoss, RecordType } from '../../model/flow-query';
 5	import { useOutsideClickEvent } from '../../utils/outside-hook';
 6	import './query-options-dropdown.css';
 7	import { QueryOptionsPanel } from './query-options-panel';
 8	
 9	export interface QueryOptionsProps {
10	  recordType: RecordType;
11	  setRecordType: (recordType: RecordType) => void;
12	  dataSource: DataSource;
13	  setDataSource: (dataSource: DataSource) => void;
14	  allowLoki: boolean;
15	  allowProm: boolean;
16	  allowFlow: boolean;
17	  allowConnection: boolean;
18	  allowPktDrops: boolean;
19	  useTopK: boolean;
20	  limit: number;
21	  setLimit: (limit: number) => void;
22	  packetLoss: PacketLoss;
23	  setPacketLoss: (pl: PacketLoss) => void;
24	}
25	
26	export const QueryOptionsDropdown: React.FC<QueryOptionsProps> = props => {
27	  const { t } = useTranslation('plugin__netobserv-plugin');
28	  const containerRef = React.useRef<HTMLDivElement>(null);
29	  const triggerRef = React.useRef<HTMLButtonElement>(null);
30	  const popperRef = React.useRef<HTMLDivElement>(null);
31	  const [isOpen, setOpen] = React.useState<boolean>(false);
32	
33	  const ref = useOutsideClickEvent(() => setOpen(false));
34	
35	  const trigger = React.useCallback(() => {
36	    return (
37	      <Button ref={triggerRef} variant="link" onClick={() => setOpen(!isOpen)} data-test="query-options-dropdown">
38	        {t('Query options')}
39	      </Button>
40	    );
41	  }, [isOpen, t]);
42	
43	  const popper = React.useCallback(() => {
44	    return (
45	      <div id="query-options-popper" ref={popperRef} className="pf-v6-c-menu" role="dialog">
46	        <QueryOptionsPanel {...props} />
47	      </div>
48	    );
49	  }, [props]);
50	
51	  return (
52	    <div id="query-options-dropdown-container" data-test="query-options-dropdown-container" ref={ref}>
53	      <div ref={containerRef}>
54	        <Popper
55	          trigger={trigger()}
56	          triggerRef={triggerRef}
57	          popper={popper()}
58	          popperRef={popperRef}
59	          isVisible={isOpen}
60	          enableFlip={true}
61	          appendTo={containerRef.current || undefined}
62	        />
63	      </div>
64	    </div>
65	  );
66	};
67	
68	export default QueryOptionsDropdown;

