 1	import { act, fireEvent, render } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { QueryOptionsDropdown, QueryOptionsProps } from '../query-options-dropdown';
 5	import { QueryOptionsPanel } from '../query-options-panel';
 6	
 7	describe('<QueryOptionsDropdown />', () => {
 8	  const props: QueryOptionsProps = {
 9	    recordType: 'allConnections',
10	    dataSource: 'auto',
11	    allowProm: true,
12	    allowLoki: true,
13	    allowFlow: true,
14	    allowConnection: true,
15	    allowPktDrops: true,
16	    useTopK: false,
17	    limit: 100,
18	    packetLoss: 'all',
19	    setLimit: jest.fn(),
20	    setPacketLoss: jest.fn(),
21	    setRecordType: jest.fn(),
22	    setDataSource: jest.fn()
23	  };
24	
25	  it('should render component', async () => {
26	    render(<QueryOptionsDropdown {...props} />);
27	    expect(document.querySelector('[data-test="query-options-dropdown-container"]')).toBeTruthy();
28	  });
29	});
30	
31	describe('<QueryOptionsPanel />', () => {
32	  const props: QueryOptionsProps = {
33	    recordType: 'allConnections',
34	    dataSource: 'auto',
35	    allowProm: true,
36	    allowLoki: true,
37	    allowFlow: true,
38	    allowConnection: true,
39	    allowPktDrops: true,
40	    useTopK: false,
41	    limit: 100,
42	    packetLoss: 'all',
43	    setLimit: jest.fn(),
44	    setPacketLoss: jest.fn(),
45	    setRecordType: jest.fn(),
46	    setDataSource: jest.fn()
47	  };
48	
49	  beforeEach(() => {
50	    props.setLimit = jest.fn();
51	  });
52	
53	  it('should render component', async () => {
54	    const { container } = render(<QueryOptionsPanel {...props} />);
55	    expect(container.querySelectorAll('.pf-v6-c-menu__group').length).toBe(4);
56	    expect(container.querySelectorAll('.pf-v6-c-menu__group-title').length).toBe(4);
57	    expect(container.querySelectorAll('input[type="radio"]')).toHaveLength(13);
58	
59	    expect(props.setLimit).toHaveBeenCalledTimes(0);
60	  });
61	
62	  it('should set options', async () => {
63	    const { container, rerender } = render(<QueryOptionsPanel {...props} />);
64	    expect(props.setLimit).toHaveBeenCalledTimes(0);
65	
66	    await act(async () => {
67	      fireEvent.click(container.querySelector('#limit-1000')!);
68	    });
69	    expect(props.setLimit).toHaveBeenNthCalledWith(1, 1000);
70	    rerender(<QueryOptionsPanel {...props} limit={1000} />);
71	  });
72	});

